import{_ as a,o,c as t,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-049 — Tiangong module pickability and scene graph","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-049.md","filePath":"adr/ADR-049.md"}'),n={name:"adr/ADR-049.md"};function s(r,e,c,d,l,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-049-—-tiangong-module-pickability-and-scene-graph" tabindex="-1">ADR-049 — Tiangong module pickability and scene graph <a class="header-anchor" href="#adr-049-—-tiangong-module-pickability-and-scene-graph" aria-label="Permalink to &quot;ADR-049 — Tiangong module pickability and scene graph&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-014 (with ADR-048, ADR-050) TA anchor · §components Related · ADR-048, ADR-041 (the ISS analogue), PRD-011</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-014 OQ-2 + OQ-5 asked how to balance pick granularity vs draw calls for Tiangong. PRD-011 / GH-50 require <strong>6 pick targets</strong>: 3 pressurised modules (Tianhe / Wentian / Mengtian) + Chinarm + 2 visiting vehicles (Shenzhou / Tianzhou). Solar arrays are scenery in V1. The small experimental arm (RFC OQ-5 option B) is deferred.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="hybrid-mesh-split-rfc-oq-2-option-c" tabindex="-1">Hybrid mesh split (RFC OQ-2 Option C) <a class="header-anchor" href="#hybrid-mesh-split-rfc-oq-2-option-c" aria-label="Permalink to &quot;Hybrid mesh split (RFC OQ-2 Option C)&quot;">​</a></h3><ol><li><strong>Pickable:</strong> one <code>THREE.Mesh</code> (or group leaf) per canonical <code>id</code> in <a href="../../static/data/tiangong-modules.json"><code>tiangong-modules.json</code></a> and <a href="../../static/data/tiangong-visitors.json"><code>tiangong-visitors.json</code></a>, with <code>userData.moduleId === id</code> and <code>userData.stationPickable === true</code>.</li><li><strong>Non-pickable:</strong> structural geometry (truss spurs, solar wings, MLI wraps) carries <code>userData.stationPickable === false</code> so the raycaster walk-up filters them out.</li></ol><h3 id="stationpickable-rename" tabindex="-1"><code>stationPickable</code> rename <a class="header-anchor" href="#stationpickable-rename" aria-label="Permalink to &quot;`stationPickable` rename&quot;">​</a></h3><p>ISS V1 used <code>userData.issPickable</code>. Since <code>/tiangong</code> reuses the same raycaster + walk-up pattern, the convention is generalised to <code>userData.stationPickable</code> and the same key is renamed in <code>iss-proxy-model.ts</code> + <code>src/routes/iss/+page.svelte</code>. The picking convention is now station-agnostic so a third station (e.g. a future Mir route) drops in with no protocol churn.</p><h3 id="highlight" tabindex="-1">Highlight <a class="header-anchor" href="#highlight" aria-label="Permalink to &quot;Highlight&quot;">​</a></h3><p><strong>OutlinePass on hover</strong> (matches <code>/iss</code> post-V1 — ADR-041&#39;s emissive-only V1 was upgraded). <strong>Emissive scale-pulse</strong> (<code>1 + sin(t · 2.6) · 0.04</code>) on the selected module when its panel is open. Unselected modules render at base scale.</p><h3 id="draw-calls" tabindex="-1">Draw calls <a class="header-anchor" href="#draw-calls" aria-label="Permalink to &quot;Draw calls&quot;">​</a></h3><p>Expect <strong>~7 pickable meshes</strong> (3 modules + Chinarm + 2 visitors + 1 merged truss-and-radiator group) — comfortably under any mobile budget.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Identical raycaster + selection logic across <code>/iss</code> and <code>/tiangong</code>; trivial per-mesh <code>userData.moduleId</code> wiring from raycast → panel.</p><p><strong>Negative:</strong> A future CMSA / Sketchfab GLB import must preserve the four module ids (<code>tianhe</code>, <code>wentian</code>, <code>mengtian</code>, <code>chinarm</code>) and two visitor ids (<code>shenzhou</code>, <code>tianzhou</code>) on its mesh names, or carry an alias table in code.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Scene traversal after <code>buildTiangongProxyStation()</code>: register pickables in a Map keyed by <code>userData.moduleId</code> for raycaster + INDEX drawer + deep-link sync. Same pattern as <code>iss-proxy-model.ts</code> post-rename.</p>',18)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
